/// Step handler trait for MediaProcessing flow
#[async_trait::async_trait]
pub trait MediaProcessingStepHandler: Send + Sync {
    /// Evaluate condition for check_media_type step
    async fn evaluate_check_media_type(
        &self,
        instance: &MediaProcessingFlowInstance,
    ) -> Result<MediaProcessingFlowStep, FlowError>;

    /// Handle create_image_thumbnail step
    async fn handle_create_image_thumbnail(
        &self,
        instance: &mut MediaProcessingFlowInstance,
    ) -> Result<Option<MediaProcessingFlowStep>, FlowError>;

    /// Handle create_video_thumbnail step
    async fn handle_create_video_thumbnail(
        &self,
        instance: &mut MediaProcessingFlowInstance,
    ) -> Result<Option<MediaProcessingFlowStep>, FlowError>;

    /// Handle create_document_preview step
    async fn handle_create_document_preview(
        &self,
        instance: &mut MediaProcessingFlowInstance,
    ) -> Result<Option<MediaProcessingFlowStep>, FlowError>;

    /// Handle terminal step no_processing_needed
    async fn handle_no_processing_needed(
        &self,
        instance: &mut MediaProcessingFlowInstance,
    ) -> Result<(), FlowError>;

    /// Handle terminal step complete
    async fn handle_complete(
        &self,
        instance: &mut MediaProcessingFlowInstance,
    ) -> Result<(), FlowError>;

}

/// Executor for MediaProcessing flow
pub struct MediaProcessingFlowExecutor<H: MediaProcessingStepHandler> {
    handler: Arc<H>,
}

impl<H: MediaProcessingStepHandler> MediaProcessingFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<MediaProcessingFlowInstance, FlowError> {
        let mut instance = MediaProcessingFlowInstance::new(instance_id);
        instance.status = MediaProcessingFlowStatus::Running;
        instance.current_step = Some(MediaProcessingFlowStep::CheckMediaType);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut MediaProcessingFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            MediaProcessingFlowStep::CheckMediaType => {
                let next = self.handler.evaluate_check_media_type(instance).await?;
                Some(next)
            }
            MediaProcessingFlowStep::CreateImageThumbnail => {
                self.handler.handle_create_image_thumbnail(instance).await?
            }
            MediaProcessingFlowStep::CreateVideoThumbnail => {
                self.handler.handle_create_video_thumbnail(instance).await?
            }
            MediaProcessingFlowStep::CreateDocumentPreview => {
                self.handler.handle_create_document_preview(instance).await?
            }
            MediaProcessingFlowStep::NoProcessingNeeded => {
                self.handler.handle_no_processing_needed(instance).await?;
                None // Terminal step
            }
            MediaProcessingFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = MediaProcessingFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut MediaProcessingFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != MediaProcessingFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut MediaProcessingFlowInstance) {
        instance.status = MediaProcessingFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut MediaProcessingFlowInstance, error: impl Into<String>) {
        instance.status = MediaProcessingFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = MediaProcessingFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, MediaProcessingFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = MediaProcessingFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = MediaProcessingFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = MediaProcessingFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = MediaProcessingFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
